function slug(t: string): string {
  return t.toLowerCase().replace(/[\u3000\s]+/g, "-").replace(/[\uff01!\uff1f?\u3002\u3001\u30fb\u300c\u300d\u300e\u300f\uff08\uff09()\u3010\u3011\[\]\uff06&\'"\uff0b\uff1d+#%@~:;\/<>{}|\^`$\\\uff1a]+/g, "").replace(/-+/g, "-").replace(/^-|-$/g, "");
}

export const n3dsGames: Game[] = raw.map(([d, t, p, genres, usedP, newP, origP, sales, desc], i) => ({
  id: `3ds-${String(i + 1).padStart(4, "0")}`,
  title: t,
  console_id: "3ds",
  publisher: p,
  developer: p,
  release_date: d,
  original_price: origP,
  genre: genres,
  description: desc,
  player_count: "1-4人",
  current_new_price: newP,
  current_used_price: usedP,
  total_sales: sales,
  premium_rank: usedP !== null && origP !== null && origP > 0
    ? usedP / origP <= 1 ? 1 : usedP / origP <= 2 ? 2 : usedP / origP <= 5 ? 3 : usedP / origP <= 10 ? 4 : 5
    : 1,
  slug: slug(t),
}));
